import string

def atbash(text):
    lowers = string.ascii_lowercase
    uppers = string.ascii_uppercase
    mapping = str.maketrans(
        lowers + uppers, lowers[::-1] + uppers[::-1]
    )
    return text.translate(mapping)

if __name__ == "__main__":
    print(f"'ABCabc' -> {atbash('ABCabc')}")
